mapper.insert:
/* com.educare.edu.comn.mapper.LectureDormiPriceMapper.insertByPk */
	insert into t_lecture_dormi_price (
		season_gb	,start_dt	,end_dt		,fee2		, fee4
	) values (
		#{seasonGb}	,#{startDt}	,#{endDt}		,#{fee2}		,#{fee4}
	)

mapper.delete:
/* com.educare.edu.comn.mapper.LectureDormiPriceMapper.updateByPk */
	update t_lecture_dormi_price 
	set fee2 = #{fee2}
		,fee4 = #{fee4}
		 	,start_dt	= #{startDt} 
		 		,end_dt		= #{endDt} 
	where season_gb = #{seasonGb}

mapper.select:
/* com.educare.edu.comn.mapper.LectureDormiPriceMapper.selectByPk */
	/** 숙소 pk 조회 */
	SELECT * FROM t_lecture_dormi_price
	WHERE  season_gb = #{seasonGb}

/* com.educare.edu.comn.mapper.LectureDormiPriceMapper.selectByAll */
	/** 숙소 all 조회 */
	SELECT * FROM t_lecture_dormi_price a
	order by case when season_gb = 'off' then 1 else 2 end asc
